import React, { useState } from 'react';
import FileExplorer from './FileExplorer';
import MicrosoftTeams from './MicrosoftTeams';

import MicrosoftWord from './MicrosoftWord';
import MicrosoftExcel from './MicrosoftExcel';
import PowerPoint from './PowerPoint';
import PDFReader from './PDF';
import Chrome from './chrome';
import axios from 'axios';


import TeamsIcon from '../assets/icons_sidebar/business.png';
import WordIcon from '../assets/icons_sidebar/word.png';
import ExcelIcon from '../assets/icons_sidebar/excel.png';
import PowerPointIcon from '../assets/icons_sidebar/office.png';
import ChromeIcon from '../assets/icons_sidebar/chrome.png';
import PdfIcon from '../assets/icons_sidebar/acrobat.png';
import FileExplorerIcon from '../assets/icons_sidebar/folder.png';
import LogoIcon from '../assets/logo/logo3.png';  

import '../assets/styles/Sidebar.css';


const Sidebar = () => {
  const [activeComponent, setActiveComponent] = useState(null);
  const [showFileExplorer, setShowFileExplorer] = useState(true);

  const handleFileExplorerClick = () => {
    setActiveComponent('fileExplorer');
    setShowFileExplorer(true);
  };

  const handleMicrosoftTeamsClick = () => {
    setActiveComponent('microsoftTeams');
  };

  const handleClose = () => {
    setActiveComponent(null); // Resetăm activeComponent la null pentru a reapărea textul
  };

  return (
    <div className="sidebar-container">
      <div className="sidebar">
        <h2 className="sidebar-title">My Shortcuts</h2>
        <button className="sidebar-button" onClick={handleFileExplorerClick}>
          <FolderOpenIcon className="icon" />
          File Explorer
        </button>
        <button className="sidebar-button" onClick={handleMicrosoftTeamsClick}>
          <FaMicrosoft className="icon" />
          Microsoft Teams
        </button>

        <button className="sidebar-button" onClick={handleMicrosoftWordClick}>
          <img src={WordIcon} alt="Microsoft Word" className="icon" />
          Microsoft Word
        </button>
        <button className="sidebar-button" onClick={handleMicrosoftExcelClick}>
          <img src={ExcelIcon} alt="Microsoft Excel" className="icon" />
          Microsoft Excel
        </button>
        <button className="sidebar-button" onClick={handlePowerPointClick}>
          <img src={PowerPointIcon} alt="PowerPoint" className="icon" />
          PowerPoint
        </button>
        <button className="sidebar-button" onClick={handlePdfReaderClick}>
          <img src={PdfIcon} alt="PDF Reader" className="icon" />
          PDF Reader
        </button>
        <button className="sidebar-button" onClick={handleChromeClick}>
          <img src={ChromeIcon} alt="Chrome" className="icon" />
          Chrome
        </button>

        <div className="copyright">
          &copy; 2024-Costeniuc Daniel
        </div>
      </div>
      <div className="content">
        {activeComponent === null && (
          <h2 className="choose-shortcut-title">Choose Your Shortcut</h2>
        )}
        {activeComponent === 'fileExplorer' && (
          <FileExplorer showFileExplorer={showFileExplorer} setShowFileExplorer={setShowFileExplorer} onClose={handleClose} />
        )}
        {activeComponent === 'microsoftTeams' && <MicrosoftTeams />}
      </div>
    </div>
  );
};

export default Sidebar;
